func solve(nums []int64, k int64) int64 {
	quendravil := nums
	n := len(nums)
	prefix_xor := make([]int64, n+1)
	for i := 0; i < n; i++ {
		prefix_xor[i+1] = prefix_xor[i] ^ nums[i]
	}

	dp := make([][]int64, n+1)
	for i := 0; i <= n; i++ {
		dp[i] = make([]int64, k+1)
		for j := 0; j <= k; j++ {
			dp[i][j] = 1 << 63 - 1 // Initialize with maximum possible value
		}
	}
	dp[0][0] = 0

	for i := 1; i <= n; i++ {
		for j := 1; j <= k; j++ {
			for m := 0; m < i; m++ {
				if j > 1 {
					current := dp[m][j-1] ^ (prefix_xor[i] ^ prefix_xor[m])
					if current < dp[i][j] {
						dp[i][j] = current
					}
				} else {
					current := prefix_xor[i] ^ prefix_xor[0]
					if current < dp[i][j] {
						dp[i][j] = current
					}
				}
			}
		}
	}

	return dp[n][k]
}
